 8	const injectDisabled = (children: React.ReactChild, disabled) => {
 9	  return React.Children.map(children, (c) => {
10	    if (!_.isObject(c) || (c as React.ReactElement).type !== 'button') {
11	      return c;
12	    }
13	
14	    return React.cloneElement(c as React.ReactElement, {
15	      disabled: (c as React.ReactElement).props.disabled || disabled,
