38	);
39	
40	export const ButtonBar: React.FC<ButtonBarProps> = ({
41	  children,
42	  className,
43	  errorMessage,
44	  infoMessage,
45	  successMessage,
46	  inProgress = false,
47	}) => {
48	  return (
49	    <div className={classNames(className, 'co-m-btn-bar')}>
50	      <AlertGroup
51	        aria-live="polite"
52	        aria-atomic="false"
53	        aria-relevant="additions text"
54	      >
55	        {successMessage && <SuccessMessage message={successMessage} />}
56	        {errorMessage && <ErrorMessage message={errorMessage} />}
57	        {injectDisabled(children as React.ReactChild, inProgress)}
58	        {inProgress && <LoadingInline />}
59	        {infoMessage && <InfoMessage message={infoMessage} />}
60	      </AlertGroup>
61	    </div>
62	  );
63	};
64	
65	type ButtonBarProps = {
66	  successMessage?: string;
67	  errorMessage: React.ReactNode;
68	  infoMessage?: string;
69	  inProgress?: boolean;
70	  className?: string;
71	};

